import{_ as a,o as e,c as i,a5 as t}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：UPS 固件实时调度（real-time scheduling）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 固件实时调度（real-time scheduling）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0022-ups-firmware-scheduler.html` 的源稿和补充资料，中文主讲。它只使用教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-firmware-scheduler.md","filePath":"content/power/concepts/embedded/ups-firmware-scheduler.md","lastUpdated":null}'),l={name:"content/power/concepts/embedded/ups-firmware-scheduler.md"};function n(p,s,o,r,h,d){return e(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="概念-ups-固件实时调度-real-time-scheduling" tabindex="-1">概念：UPS 固件实时调度（real-time scheduling） <a class="header-anchor" href="#概念-ups-固件实时调度-real-time-scheduling" aria-label="Permalink to &quot;概念：UPS 固件实时调度（real-time scheduling）&quot;">​</a></h1><p>本页是 <code>lessons/0022-ups-firmware-scheduler.html</code> 的源稿和补充资料，中文主讲。它只使用教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据；学习记录中也不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>控制中断服务程序（control interrupt service routine / control ISR）是按固定控制周期运行的实时路径。后台任务（background task）是低优先级、低频或可被打断的软件任务，例如遥测、通信、参数保存和日志整理。</p><p>实时调度（real-time scheduling）关心的不是“平均能跑完”，而是关键任务每次都必须在截止时间前跑完。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）同时有功率控制、保护、状态机、通信和日志。逆变器电压环、功率因数校正（power factor correction / PFC）电流环、脉宽调制（pulse-width modulation / PWM）更新和模数转换器采样（analog-to-digital converter / ADC sampling）都要求稳定时序。</p><p>如果通信任务阻塞控制 ISR，可能造成 PWM 更新抖动、保护延迟、控制相位滞后，最后表现成波形变差或保护误动作。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>控制 ISR 像心跳，周期短且不能漏拍；后台任务像体检报告，可以慢一些，但不能挡住心跳。UPS 固件要让快路径只做必须实时完成的动作，把通信、显示、日志这类慢路径移出 ISR。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>控制周期：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T_control = 1 / f_control</span></span></code></pre></div><p>ISR 执行时间预算：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>t_isr = t_adc + t_control + t_protection + t_pwm_update</span></span>
<span class="line"><span>margin = budget_isr - t_isr</span></span>
<span class="line"><span>deadline_miss = margin &lt; 0</span></span></code></pre></div><p>默认仿真参数：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>f_control = 10 kHz</span></span>
<span class="line"><span>f_telemetry = 200 Hz</span></span>
<span class="line"><span>f_comm = 50 Hz</span></span>
<span class="line"><span>ISR budget = 70 us</span></span></code></pre></div><h2 id="_5-仿真观察" tabindex="-1">5. 仿真观察 <a class="header-anchor" href="#_5-仿真观察" aria-label="Permalink to &quot;5. 仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_firmware_scheduler.py</span></span></code></pre></div><p>脚本默认生成并尝试自动打开：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_firmware_scheduler.png</span></span></code></pre></div><p>图中第一栏显示控制 ISR 执行时间与预算；第二栏显示 ADC、保护和 PWM 更新事件；第三栏显示遥测任务和通信任务；第四栏显示故障锁存与后台负载。</p><p>可故意制造超时：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_firmware_scheduler.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">control</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">time</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">us </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">52</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\ups_scheduler_deadline_fail.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_firmware_scheduler.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">communication</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">frequency </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">200</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\ups_scheduler_comm_200hz.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>一个仿真任务：对比默认图、<code>ups_scheduler_deadline_fail.png</code> 和 <code>ups_scheduler_comm_200hz.png</code>。重点判断“ISR 超时”和“后台通信变密”是不是同一类问题。</p><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>读 C 工程时可按这个顺序找：</p><ul><li><code>isr.c</code> 或 <code>control.c</code>：控制 ISR，包含 ADC 结果读取、保护快速判断、控制计算、PWM 更新。</li><li><code>scheduler.c</code>：周期任务调度标志，例如 1 ms、10 ms、100 ms 任务。</li><li><code>communication.c</code>：通信任务（communication task），不应长时间占用中断。</li><li><code>protection.c</code>：快速保护和锁存保护的边界。</li><li><code>log.c</code>：故障发生后的证据记录。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li>错误理解：控制频率 10 kHz，只要 CPU 平均占用不高就没问题。<br> 正确理解：实时任务看最坏情况截止时间，某一次 ISR 超时也可能破坏 PWM 更新。</li><li>错误理解：通信任务放进 ISR 最稳。<br> 正确理解：通信帧处理时间长且抖动大，通常应放后台或低优先级中断。</li><li>错误理解：保护逻辑全部放后台任务也可以。<br> 正确理解：快速过流、过压等风险通常要在硬件比较器或控制 ISR 快路径处理。</li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释控制 ISR、后台任务、实时调度的分工。</li><li>能根据图中的 <code>ISR budget</code> 和执行时间判断是否超时。</li><li>能说明为什么通信任务不应阻塞控制 ISR。</li><li>能基于 <code>ups_firmware_scheduler.png</code> 准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>默认仿真中，控制周期是多少微秒？ISR 执行时间是多少微秒？剩余裕量是多少？</li><li>为什么通信任务执行时间可以大于 ISR 预算，却不一定造成 ISR deadline miss？</li><li>把 <code>--control-time-us</code> 改为 52 后，图标题里的 deadline 状态如何变化？这说明什么？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>ups_firmware_scheduler.py</code> 看到通信任务默认 50 Hz，执行时间比 ISR 预算长，所以它被放在后台。公司工程里通信任务一般由主循环、RTOS 任务还是低优先级中断处理？</li><li>我把 <code>--control-time-us</code> 改到 52 后图中出现 deadline fail。真实工程里通常怎样测量控制 ISR 的最坏执行时间？</li><li>如果保护既有硬件比较器又有软件阈值，公司代码里快速保护和状态机锁存之间如何分层？</li></ul>`,37)])])}const k=a(l,[["render",n]]);export{u as __pageData,k as default};
